8103 static bool isKnownNonNaN(const Value *V, FastMathFlags FMF) {
8104   if (FMF.noNaNs())
8105     return true;
8106 
8107   if (auto *C = dyn_cast<ConstantFP>(V))
8108     return !C->isNaN();
8109 
8110   if (auto *C = dyn_cast<ConstantDataVector>(V)) {
8111     if (!C->getElementType()->isFloatingPointTy())
8112       return false;
8113     for (unsigned I = 0, E = C->getNumElements(); I < E; ++I) {
8114       if (C->getElementAsAPFloat(I).isNaN())
8115         return false;
8116     }
8117     return true;
8118   }
8119 
8120   if (isa<ConstantAggregateZero>(V))
8121     return true;
8122 
8123   return false;
8124 }
